INSERT OR REPLACE INTO characters (id, covenant_id, name, character_type, house, birth_year, death_year, description, favored_arts, familiar_link, apprentice_registry, biographical_notice, source_book, page_reference, is_official, is_active)
VALUES
('magus-census-0001', 'cov-coeris-0000', 'Darius', 'magus', 'Flambeau', 1182, 1254, 'Grand, athlétique, regard farouche. Porte une armure de cuir souple enchantée et une épée bâtarde.', 'Ignem & Perdo', 'Aucun', 'Aucun', 'Archétype du chasseur de monstres de l''École de Ramius, dévoué à l''éradication des menaces infernales.', 'Ars Magica 5th Edition Core Rulebook', 'p. 34', 1, 1),
('magus-census-0002', 'cov-valnastium-0000', 'Alexander', 'magus', 'Jerbiton', 1178, 1248, 'Aristocrate raffiné au port altier, vêtu de soies de Florence brodées de fils d''argent.', 'Mentem & Imaginem', 'Un faucon pèlerin magique', 'Beatrix', 'Diplomate hermétique accompli, spécialisé dans l''apaisement des tensions entre les mages et la noblesse laïque.', 'Ars Magica 5th Edition Core Rulebook', 'p. 35', 1, 1),
('magus-census-0003', 'cov-verdi-0000', 'Gideon', 'magus', 'Verditus', 1185, 1260, 'Mains calleuses d''artisan, dos voûté par le travail à l''enclume, porte d''épais anneaux de focalisation.', 'Terram & Creo', 'Un automate de corbeau animé', 'Aucun', 'Artisan de talent capable de réduire drastiquement le coût en Vis lors de la forge d''artefacts minéraux.', 'Ars Magica 5th Edition Core Rulebook', 'p. 35', 1, 1),
('magus-census-0004', 'cov-semitae-0000', 'Aururentius', 'magus', 'Ex Miscellanea', 1172, 1244, 'Peau hâlée par les tempêtes, ses cheveux crépitent occasionnellement de décharges statiques.', 'Auram & Creo', 'Un petit esprit de foudre lié', 'Aucun', 'Surnommé le Maître de la Foudre, issu d''une tradition locale de sorciers du climat d''Angleterre.', 'Magi of Hermes', 'p. 15', 1, 1),
('magus-census-0005', 'cov-krasnorechye-0000', 'Conna', 'magus', 'Bjornaer', 1152, 1238, 'Visage buriné par les hivers, comportement farouche, tics animaux. Heartbeast : Ours brun.', 'Muto & Animal', 'Aucun (Interdit par la Maison)', 'Uvari', 'Ancienne ayant choisi de vivre au cœur de la taïga sauvage, fusionnant les structures rocheuses avec le corps animal.', 'Magi of Hermes', 'p. 24', 1, 1),
('magus-census-0006', 'cov-castrasolis-0000', 'Gaston', 'magus', 'Flambeau', 1190, 1262, 'Jeune chevalier fougueux arborant une cape rouge écarlate, épée de duel enchantée.', 'Creo & Ignem', 'Un épervier magique', 'Aucun', 'Spécialiste de la création de feux purs et de l''art de la joute magique codifiée (*Hastiludia*).', 'Magi of Hermes', 'p. 38', 1, 1),
('magus-census-0007', 'cov-fudarus-0000', 'Gora', 'magus', 'Tytalus', 1165, 1235, 'Regard d''acier froid, vêtue de robes de bure grises minimalistes, posture rigide.', 'Mentem & Perdo', 'Aucun (Refus stratégique)', 'Anonyme', 'Experte en manipulation mentale et en destruction psychologique de ses rivaux lors des tribunaux.', 'Magi of Hermes', 'p. 61', 1, 1),
('magus-census-0008', 'cov-magvillus-0000', 'Julia', 'magus', 'Guernicus', 1180, 1251, 'Stricte, cheveux tirés en chignon serré, porte le Code d''Hermès gravé sur de fines tablettes de marbre.', 'Intellego & Vim', 'Un dogue blanc magique', 'Marcus', 'Quaesitor intègre dédiée à l''investigation magique et à la détection des crimes de spoliation de Vis.', 'Magi of Hermes', 'p. 72', 1, 1),
('magus-census-0009', 'cov-pythagoranis-0000', 'Lambert', 'magus', 'Verditus', 1190, 1268, 'Petit, fortement voûté, porte d''épaisses bésicles de verre pour les travaux d''horlogerie fine.', 'Rego & Terram', 'Chronos (Corbeau mémorial)', 'Gideon', 'Le plus grand concepteur d''automates mécaniques temporels et d''engrenages autonomes de l''Ordre.', 'Magi of Hermes', 'p. 83', 1, 1),
('magus-census-0010', 'cov-exspectatio-0000', 'Maris', 'magus', 'Ex Miscellanea', 1192, 1260, 'Peau tannée par le sel, cheveux tressés avec des coquillages chargés magiquement.', 'Rego & Aquam', 'Un goéland argenté géant', 'Aucun', 'Pisteur des vagues issu des traditions maritimes bretonnes, capable de calmer les tempêtes côtières.', 'Magi of Hermes', 'p. 94', 1, 1),
('magus-census-0011', 'cov-twisting-0000', 'Muscaria', 'magus', 'Criamon', 1160, 1229, 'Totalement chauve, crâne entièrement couvert de tatouages géométriques bleus, s''exprime par énigmes.', 'Intellego & Mentem', 'Un lézard aveugle', 'Silas', 'Mystique absorbée par la contemplation de l''Énigme et les distorsions temporelles de la conscience.', 'Magi of Hermes', 'p. 105', 1, 1),
('magus-census-0012', 'cov-verdi-0000', 'Petalichus', 'magus', 'Verditus', 1176, 1249, 'Artisan précieux, tablier de cuir brodé de runes d''argent, doigts fins d''orfèvre.', 'Muto & Terram', 'Une belette magique rousse', 'Aucun', 'Ciseleur d''exception, spécialisé dans l''enchantement de gemmes précieuses et de bijoux royaux.', 'Magi of Hermes', 'p. 116', 1, 1),
('magus-census-0013', 'cov-castrasolis-0000', 'Ranulf', 'magus', 'Flambeau', 1184, 1261, 'Cheveux roux ardents, yeux étincelants, mains marquées par la manipulation de la lave.', 'Creo & Ignem', 'Artesano (Salamandre magique)', 'Ignatius', 'Inventeur de la doctrine des *Feux Unnaturels*, des flammes capables de brûler sous l''eau ou d''adopter des trajectoires impossibles.', 'Magi of Hermes', 'p. 127', 1, 1),
('magus-census-0014', 'cov-irencilia-0000', 'Scipio', 'magus', 'Merinita', 1180, 1252, 'Sourire mystique permanent, s''habille de tuniques tressées à partir de lierre et de branches vivantes.', 'Creo & Imaginem', 'Une araignée tisseuse de charmes faës', 'Anonyme', 'Maître du *Glamour*, capable d''altérer la perception de la réalité en introduisant des essences d''Arcadia.', 'Magi of Hermes', 'p. 138', 1, 1),
('magus-census-0015', 'cov-doissetep-0000', 'Tolides', 'magus', 'Flambeau', 1170, 1244, 'Musclé, cicatrice sur la joue gauche, porte une cotte de mailles d''un blanc étincelant.', 'Perdo & Ignem', 'Varg (Loup de chasse magique)', 'Valerius', 'Surnommé le Fléau des Monstres, adepte de l''extermination brute des créatures infernales.', 'Magi of Hermes', 'p. 149', 1, 1),
('magus-census-0016', 'cov-durenmar-0000', 'Varia', 'magus', 'Bonisagus', 1198, 1270, 'Jeune femme studieuse aux grandes bésicles, doigts perpétuellement maculés de craie et de soufre.', 'Muto & Vim', 'Un hibou blanc parleur', 'Aucun', 'Chercheuse émérite spécialisée dans la modification structurelle des formules magiques hermétiques.', 'Magi of Hermes', 'p. 160', 1, 1),
('magus-census-0017', 'cov-durenmar-0000', 'Murion', 'magus', 'Bonisagus (Prima)', 1142, 1265, 'Cheveux d''argent tressés, toge blanche et or, présence politique et intellectuelle imposante.', 'Rego & Vim', 'Aucun (entièrement dévouée au Code)', 'Maîtres de laboratoire', 'Prima de Bonisagus et dirigeante politique de Durenmar. Gardienne absolue des archives de l''Ordre.', 'Guardians of the Forests: The Rhine Tribunal', 'p. 14', 1, 1),
('magus-census-0018', 'cov-durenmar-0000', 'Philippus Niger', 'magus', 'Flambeau (Archimage)', 1095, 1225, 'Silhouette massive, barbe noire d''encre, armure de plates sombres enchantée.', 'Perdo & Ignem', 'Aucun (solitaire)', 'Tolides', 'Le célèbre Défenseur de Durenmar. Maître de l''École d''Apromor, spécialisé dans l''extinction des feux et le froid destructeur.', 'Guardians of the Forests: The Rhine Tribunal', 'p. 42', 1, 1),
('magus-census-0019', 'cov-durenmar-0000', 'Ochren', 'magus', 'Bonisagus', 1165, 1238, 'Visage émacié, dos fortement voûté, yeux injectés de sang par la lecture nocturne de grimoires.', 'Creo & Intellego', 'Un hibou des clochers', 'Janus', 'Chercheur obsédé par la restauration des textes originaux dégradés de Bonisagus.', 'Guardians of the Forests: The Rhine Tribunal', 'p. 45', 1, 1),
('magus-census-0020', 'cov-fengheld-0000', 'Vinaria', 'magus', 'Bonisagus', 1178, 1249, 'Grande, robes herboristes vertes, dégage une forte odeur de mousse forestière et de sève.', 'Creo & Herbam', 'Une loutre de rivière magique', 'Carolus', 'Botaniste magique, experte dans la culture d''arbres à Vis au sein du Tribunal du Rhin.', 'Guardians of the Forests: The Rhine Tribunal', 'p. 55', 1, 1),
('magus-census-0021', 'cov-crintera-0000', 'Falke', 'magus', 'Bjornaer (Prima)', 1155, 1258, 'Traits anguleux, yeux ambrés de rapace, vêtue de peaux brutes. Heartbeast : Faucon pèlerin.', 'Muto & Animal', 'Aucun (Règle Bjornaer)', 'Initiés de Rügen', 'Prima de la Maison Bjornaer, dirige l''alliance sauvage de Crintera et défend les traditions ancestrales changeuses de forme.', 'Guardians of the Forests: The Rhine Tribunal', 'p. 68', 1, 1),
('magus-census-0022', 'cov-irencilia-0000', 'Handen', 'magus', 'Merinita (Primus)', 1150, 1236, 'Regard changeant selon la lumière, couronne de branches et de feuilles d''automne entrelacées.', 'Rego & Mentem', 'Puck (Farfadet des bois)', 'Scipio', 'Primus de Merinita, il maintient l''alliance d''Irencilia en contact étroit avec les seigneurs faës d''Allemagne.', 'Guardians of the Forests: The Rhine Tribunal', 'p. 80', 1, 1),
('magus-census-0023', 'cov-fengheld-0000', 'Horst', 'magus', 'Mercere', 1170, 1233, 'Homme trapu, visage jovial, porte toujours une Toque Rouge neuve et une sacoche scellée.', 'Aucun (Redcap)', 'Un grand chien de berger', 'Simeon', 'Toque Rouge officielle du Rhin, responsable de la distribution des messages de la Guilde de l''Appeau.', 'Guardians of the Forests: The Rhine Tribunal', 'p. 52', 1, 1),
('magus-census-0024', 'cov-fengheld-0000', 'Eule', 'magus', 'Bjornaer', 1182, 1245, 'Petite, se déplace sans bruit, grands yeux ronds et fixes. Heartbeast : Chouette hulotte.', 'Intellego & Animal', 'Aucun (Interdit)', 'Aucun', 'Spécialisée dans la surveillance nocturne et l''espionnage sensoriel pour le compte de Fengheld.', 'Guardians of the Forests: The Rhine Tribunal', 'p. 52', 1, 1),
('magus-census-0025', 'cov-levrier-0000', 'Prospero', 'magus', 'Jerbiton', 1158, 1231, 'Barbe grise soignée, vêtements de soie fine de conseiller ducal, voix posée et harmonieuse.', 'Creo & Mentem', 'Nestor (Hibou grand-duc)', 'Thomas', 'Diplomate majeur s''opposant à la vassalité hermétique de Fudarus, conseiller secret à la cour de Normandie.', 'The Lion and the Lily: The Normandy Tribunal', 'p. 56', 1, 1),
('magus-census-0026', 'cov-exspectatio-0000', 'Iasper', 'magus', 'Tytalus', 1195, 1268, 'Jeune homme au regard provocateur, vêtements de cuir de voyage robustes, dagues dissimulées.', 'Rego & Corpus', 'Aucun (Considéré comme faiblesse)', 'Aucun', 'Mage Tytalus agressif gérant l''alliance vassale de frontière, expert en défis corporels.', 'The Lion and the Lily: The Normandy Tribunal', 'p. 68', 1, 1),
('magus-census-0027', 'cov-fudarus-0000', 'Tasgillia', 'magus', 'Tytalus', 1176, 1245, 'Femme athlétique, cheveux courts noirs, regard froid et calculateur, experte en herboristerie toxique.', 'Perdo & Corpus', 'Une vipère magique des sables', 'Aucun', 'Bras droit de la Prima de Fudarus, chargée de tester la résilience des apprentis par des poisons contrôlés.', 'The Lion and the Lily: The Normandy Tribunal', 'p. 44', 1, 1),
('magus-census-0028', 'cov-fudarus-0000', 'Buliste', 'magus', 'Tytalus (Prima)', 1148, 1224, 'Vieille femme au port altier, regard glacial, s''habille de lourdes voiles de soie noire.', 'Perdo & Mentem', 'Un corbeau charognard géant', 'Tasgillia', 'Prima de la Maison Tytalus. Elle maintient Fudarus comme un pôle de conflit permanent pour endurcir l''Ordre.', 'The Lion and the Lily: The Normandy Tribunal', 'p. 42', 1, 1),
('magus-census-0029', 'cov-coeris-0000', 'Poenitus', 'magus', 'Tremere (Primus)', 1138, 1262, 'Carrure militaire impeccable, cheveux rasés à la romaine, toge de cuir rouge cérémonielle.', 'Rego & Corpus', 'Aucun (Discipline militaire)', 'Structure collégiale', 'Primus de la Maison Tremere, commandant suprême des vexillations de grogs et des mages de guerre.', 'Against the Dark: The Transylvania Tribunal', 'p. 38', 1, 1),
('magus-census-0030', 'cov-coeris-0000', 'Txeru', 'magus', 'Tremere', 1162, 1235, 'Homme taciturne au visage marqué par les vents des Balkans, regard d''acier fixe.', 'Rego & Vim', 'Un aigle royal magique', 'Justinius', 'Stratège en chef spécialisé dans le déploiement de boucliers rituels hermétiques contre le surnaturel.', 'Against the Dark: The Transylvania Tribunal', 'p. 42', 1, 1),
('magus-census-0031', 'cov-kastellon-0000', 'Cercistus', 'magus', 'Tremere', 1198, 1260, 'Jeune officier hermétique, armure légère de cuir bouilli runique, démarche rigide.', 'Rego & Terram', 'Aucun', 'Aucun', 'Mage de garnison chargé de la maintenance des herses et des fortifications magiques de Kastellon.', 'Against the Dark: The Transylvania Tribunal', 'p. 45', 1, 1),
('magus-census-0032', 'cov-valnegra-0000', 'Berengarius', 'magus', 'Flambeau', 1140, 1222, 'Vieillard couvert de cicatrices, bras gauche amputé remplacé par une prothèse de bronze gravée.', 'Perdo & Ignem', 'Un faucon de guerre aveugle', 'Aucun', 'Ancien combattant de la Guerre du Schisme, gardien des ruines et des reliques brisées de Val-Negra.', 'Faith and Flame: The Provence Tribunal', 'p. 48', 1, 1),
('magus-census-0033', 'cov-castrasolis-0000', 'Garsias', 'magus', 'Flambeau', 1172, 1239, 'Stature imposante, barbe noire taillée carrée, porte une épée lourde enchantée de reflets ardents.', 'Creo & Ignem', 'Une salamandre de feu', 'Ranulf', 'Maître d''armes réputé du tribunal, organisateur des tournois hermétiques régionaux (*Hastiludia*).', 'Faith and Flame: The Provence Tribunal', 'p. 72', 1, 1),
('magus-census-0034', 'cov-favras-0000', 'Christophoros', 'magus', 'Criamon', 1185, 1250, 'Sourd-muet, communique par gestes lents, tatouages de cercles dorés concentriques sur le visage.', 'Muto & Imaginem', 'Un caméléon magique', 'Aucun', 'Mystique dédié à la déconstruction des illusions sensorielles pour atteindre la vérité interne de l''Énigme.', 'The Sundered Eagle: The Thebes Tribunal', 'p. 92', 1, 1),
